import { useState, useEffect } from 'react';

function Home() {
  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex items-center justify-between">
        {/* Images left */}
        <div className="h-full relative flex items-center">
          <div className="ml-40 relative">
            <img
              id="image-1"
              className="rounded-lg transition-transform transform"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              id="image-2"
              className="rounded-lg absolute animate-float"
              width={150}
              height={150}
              style={{
                top: `calc(50% - 75px)`,
                left: `calc(-35%)`,
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              id="image-3"
              className="rounded-lg absolute animate-float"
              width={150}
              height={150}
              style={{
                top: `calc(90%)`,
                left: `calc(50% - 75px)`,
              }}
              src="/Foto4.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5">
          <h3 className="text-[#6d7561] md:text-3xl font-medium text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-4xl md:text-4xl font-bold text-center">
            Anto & Kevin
          </h1>
          <a
            href="#ConfirmAttendance"
            className="text-[#6d7561] text-2xl underline hover:text-[#6d756190]"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        {/* Images right */}
        <div className="h-full relative flex items-center justify-end">
          <div className="mr-40 relative">
            <img
              className="rounded-lg"
              width={300}
              height={250}
              src="/Foto1.HEIC"
              alt="Imagen 1"
            />
            <img
              width={200}
              height={200}
              className="rounded-lg absolute animate-float"
              style={{
                top: 'calc(50% - 100px)',
                right: `calc(0% - 150px)`,
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
